import{_ as i,H as o,f as t,i as a}from"./chunks/framework.CKQqA5tu.js";const g=JSON.parse('{"title":"快速上手","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md"}'),s={name:"guide/getting-started.md"};function d(l,e,n,r,c,p){return o(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h1><p>欢迎使用 <code>unibestX</code>，这是一个基于 uni-app X 的现代开发模板。本指南将帮助您快速在本地运行项目。</p><h2 id="⚙️-环境准备" tabindex="-1">⚙️ 环境准备 <a class="header-anchor" href="#⚙️-环境准备" aria-label="Permalink to &quot;⚙️ 环境准备&quot;">​</a></h2><p>在开始之前，请确保您的开发环境满足以下要求：</p><ul><li><strong>Node.js</strong>: <code>&gt;= 22</code></li><li><strong>包管理器</strong>: <code>pnpm &gt;= 7.30</code></li><li><strong>IDE</strong>: <code>HBuilderX = 5.0.7</code><div class="warning custom-block github-alert"><p class="custom-block-title">注意</p><p>目前大于 5.0.7 的版本在安卓编译上存在一些问题，强烈建议下载并使用 5.0.7 版本。</p></div></li><li><strong>Vue Official</strong>: <code>&gt;= 2.1.10</code></li><li><strong>TypeScript</strong>: <code>&gt;= 5.0</code></li><li><strong>特定平台依赖</strong>: <ul><li><strong>Android</strong>: JDK &gt;= 17, Android SDK</li><li><strong>iOS</strong>: Xcode (仅 macOS 支持)</li><li><strong>鸿蒙</strong>: DevEco Studio</li></ul></li></ul><h2 id="📂-快速开始" tabindex="-1">📂 快速开始 <a class="header-anchor" href="#📂-快速开始" aria-label="Permalink to &quot;📂 快速开始&quot;">​</a></h2><h3 id="_1-克隆项目" tabindex="-1">1. 克隆项目 <a class="header-anchor" href="#_1-克隆项目" aria-label="Permalink to &quot;1. 克隆项目&quot;">​</a></h3><p>将项目克隆到本地计算机：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/cq112233/unibestX.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> unibestX</span></span></code></pre></div><h3 id="_2-安装依赖" tabindex="-1">2. 安装依赖 <a class="header-anchor" href="#_2-安装依赖" aria-label="Permalink to &quot;2. 安装依赖&quot;">​</a></h3><p>在控制台中执行以下命令，使用 <code>pnpm</code> 安装项目所需的 Node 依赖：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><h3 id="_3-打开项目" tabindex="-1">3. 打开项目 <a class="header-anchor" href="#_3-打开项目" aria-label="Permalink to &quot;3. 打开项目&quot;">​</a></h3><p>使用 <strong>HBuilderX</strong> 打开克隆下来的项目根目录。</p><h2 id="📦-运行项目-支持热更新" tabindex="-1">📦 运行项目（支持热更新） <a class="header-anchor" href="#📦-运行项目-支持热更新" aria-label="Permalink to &quot;📦 运行项目（支持热更新）&quot;">​</a></h2><p>在 HBuilderX 的顶部菜单栏中，您可以选择不同的平台来启动运行：</p><ul><li><strong>Android 平台</strong>：选择 <code>运行</code> → <code>运行到手机或模拟器</code>，然后选择目标安卓设备。</li><li><strong>iOS 平台</strong>：选择 <code>运行</code> → <code>运行到手机或模拟器</code>，选择 iOS 设备。</li><li><strong>鸿蒙平台</strong>：选择 <code>运行</code> → <code>运行到手机或模拟器</code>，选择鸿蒙设备。</li><li><strong>H5 平台</strong>：选择 <code>运行</code> → <code>运行到浏览器</code>。</li><li><strong>微信小程序</strong>：选择 <code>运行</code> → <code>运行到小程序模拟器</code> → <code>微信开发者工具</code>。</li></ul><h2 id="🔗-发布构建" tabindex="-1">🔗 发布构建 <a class="header-anchor" href="#🔗-发布构建" aria-label="Permalink to &quot;🔗 发布构建&quot;">​</a></h2><p>完成开发后，您可以通过以下方式打包发布：</p><ul><li><strong>Android 平台</strong>：选择 <code>发行</code> → <code>原生App-云打包</code> 或 <code>原生App-本地打包</code>。</li><li><strong>iOS 平台</strong>：选择 <code>发行</code> → <code>原生App-云打包</code>（需 Apple 开发者证书）。</li><li><strong>鸿蒙平台</strong>：选择 <code>发行</code> → <code>原生App-鸿蒙</code>。</li><li><strong>H5 平台</strong>：选择 <code>发行</code> → <code>网站-H5手机版</code>，打包后的文件将生成在 <code>dist/build/h5</code> 目录下。</li><li><strong>微信小程序</strong>：选择 <code>发行</code> → <code>小程序-微信</code>，然后通过微信开发者工具上传代码。</li></ul>`,20)])])}const u=i(s,[["render",d]]);export{g as __pageData,u as default};
